import sys

def solve():
    data = sys.stdin.read().split()
    n, m = int(data[0]), int(data[1])
    a = data[2]
    b = data[3]

    L = n - m + 1
    INF = float('inf')

    cost = [sum(1 for j in range(m) if a[i+j] != b[j]) for i in range(L)]

    # Check if two "on" positions with gap d are consistent
    def consistent(d):
        if d >= m:
            return True
        return b[d:] == b[:m-d]

    # Incremental cost: given prev is "on", make cur "on" too
    def inc_cost(prev, cur):
        d = cur - prev
        if not consistent(d):
            return INF
        if d >= m:
            return cost[cur]
        # New chars are positions cur to prev+m-1 (indices d..m-1 of b from prev's perspective)
        # Actually new chars added: a[prev+m .. cur+m-1] vs b[m-d .. m-1]
        return sum(1 for j in range(d) if a[prev + m + j] != b[m - d + j])

    # Cost to break an accidental match at position p, given surrounding "on" positions
    # After fixing on-positions, some chars at p are forced; check if it matches b
    def break_cost(p, prev_on, next_on):
        chars = list(a[p:p+m])
        if prev_on >= 0 and prev_on + m > p:
            for j in range(min(prev_on + m - p, m)):
                chars[j] = b[p - prev_on + j]
        if next_on < L and next_on < p + m:
            for j in range(max(0, next_on - p), m):
                chars[j] = b[j - (next_on - p)]
        if chars == list(b):
            return 1
        return 0

    # dp[i][k]: last on is i, exactly k ons so far
    dp = [[INF] * (L + 2) for _ in range(L)]
    for i in range(L):
        dp[i][1] = cost[i]

    for i in range(1, L):
        for j in range(i):
            ic = inc_cost(j, i)
            if ic == INF:
                continue
            for k in range(1, j + 2):
                if dp[j][k] < INF:
                    # Add break costs for off positions between j and i
                    extra = sum(break_cost(p, j, i) for p in range(j+1, i))
                    val = dp[j][k] + ic + extra
                    if val < dp[i][k+1]:
                        dp[i][k+1] = val

    results = []
    for target_k in range(L + 1):
        if target_k == 0:
            best = sum(break_cost(p, -1, L) for p in range(L))
            results.append(best)
        else:
            best = INF
            for i in range(L):
                if dp[i][target_k] < INF:
                    extra = sum(break_cost(p, i, L) for p in range(i+1, L))
                    val = dp[i][target_k] + extra
                    best = min(best, val)
            results.append(best if best < INF else -1)

    print(' '.join(str(x) if x != -1 and x < INF else '-1' for x in results))

solve()

